import{_ as t,o as a,c as o,a3 as i}from"./chunks/framework.DxStgKjp.js";const u=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"clice/guide/configuration.md","filePath":"en/clice/guide/configuration.md"}'),r={name:"clice/guide/configuration.md"};function d(s,e,c,n,l,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>clice reads configuration from <code>clice.toml</code> in the workspace root. Configuration can also be passed via LSP <code>initializationOptions</code> (JSON format).</p><h2 id="variable-substitution" tabindex="-1">Variable Substitution <a class="header-anchor" href="#variable-substitution" aria-label="Permalink to &quot;Variable Substitution&quot;">​</a></h2><p>The following variable is supported in string values:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>${workspace}</code></td><td>The workspace directory provided by the client</td></tr></tbody></table><h2 id="project" tabindex="-1">Project <a class="header-anchor" href="#project" aria-label="Permalink to &quot;Project&quot;">​</a></h2><h3 id="project-clang-tidy" tabindex="-1"><code>project.clang_tidy</code> <a class="header-anchor" href="#project-clang-tidy" aria-label="Permalink to &quot;`project.clang_tidy`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>bool</code></td><td><code>false</code></td></tr></tbody></table><p>Enable experimental clang-tidy diagnostics. <strong>Not yet wired</strong> — the option is parsed but has no effect currently.</p><h3 id="project-max-active-file" tabindex="-1"><code>project.max_active_file</code> <a class="header-anchor" href="#project-max-active-file" aria-label="Permalink to &quot;`project.max_active_file`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>int</code></td><td><code>8</code></td></tr></tbody></table><p>Maximum number of active files to keep in memory. <strong>Not yet wired</strong> — the option is parsed but the worker still uses a hardcoded limit.</p><h3 id="project-cache-dir" tabindex="-1"><code>project.cache_dir</code> <a class="header-anchor" href="#project-cache-dir" aria-label="Permalink to &quot;`project.cache_dir`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>string</code></td><td><code>$XDG_CACHE_HOME/clice/&lt;hash&gt;</code> or <code>${workspace}/.clice</code></td></tr></tbody></table><p>Directory for storing PCH and PCM cache files. The default uses XDG_CACHE_HOME (or <code>~/.cache</code>) with a workspace-specific hash subdirectory. Falls back to <code>${workspace}/.clice</code> if the XDG directory cannot be created.</p><h3 id="project-index-dir" tabindex="-1"><code>project.index_dir</code> <a class="header-anchor" href="#project-index-dir" aria-label="Permalink to &quot;`project.index_dir`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>string</code></td><td><code>${cache_dir}/index</code></td></tr></tbody></table><p>Directory for storing index files.</p><h3 id="project-logging-dir" tabindex="-1"><code>project.logging_dir</code> <a class="header-anchor" href="#project-logging-dir" aria-label="Permalink to &quot;`project.logging_dir`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>string</code></td><td><code>${cache_dir}/logs</code></td></tr></tbody></table><p>Directory for log files.</p><h3 id="project-compile-commands-paths" tabindex="-1"><code>project.compile_commands_paths</code> <a class="header-anchor" href="#project-compile-commands-paths" aria-label="Permalink to &quot;`project.compile_commands_paths`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>array of string</code></td><td><code>[]</code></td></tr></tbody></table><p>Paths to search for <code>compile_commands.json</code> files. Entries can be direct file paths or directories (clice looks for <code>compile_commands.json</code> inside). When empty (the default), clice searches the workspace root and then each of its immediate subdirectories, using the first <code>compile_commands.json</code> it finds.</p><h3 id="project-enable-indexing" tabindex="-1"><code>project.enable_indexing</code> <a class="header-anchor" href="#project-enable-indexing" aria-label="Permalink to &quot;`project.enable_indexing`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>bool</code></td><td><code>true</code></td></tr></tbody></table><p>Enable background indexing for cross-TU features (find references, workspace symbols, etc.).</p><h3 id="project-idle-timeout-ms" tabindex="-1"><code>project.idle_timeout_ms</code> <a class="header-anchor" href="#project-idle-timeout-ms" aria-label="Permalink to &quot;`project.idle_timeout_ms`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>int</code></td><td><code>3000</code></td></tr></tbody></table><p>Idle time (milliseconds) before starting background indexing after the last edit.</p><h3 id="project-stateful-worker-count" tabindex="-1"><code>project.stateful_worker_count</code> <a class="header-anchor" href="#project-stateful-worker-count" aria-label="Permalink to &quot;`project.stateful_worker_count`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>uint32</code></td><td><code>2</code></td></tr></tbody></table><p>Number of stateful worker processes. These hold ASTs in memory and serve queries (hover, semantic tokens, etc.).</p><h3 id="project-stateless-worker-count" tabindex="-1"><code>project.stateless_worker_count</code> <a class="header-anchor" href="#project-stateless-worker-count" aria-label="Permalink to &quot;`project.stateless_worker_count`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>uint32</code></td><td><code>max(cores/2, 2)</code></td></tr></tbody></table><p>Number of stateless worker processes. These handle ephemeral tasks (PCH/PCM builds, completion, signature help).</p><h3 id="project-worker-memory-limit" tabindex="-1"><code>project.worker_memory_limit</code> <a class="header-anchor" href="#project-worker-memory-limit" aria-label="Permalink to &quot;`project.worker_memory_limit`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>uint64</code></td><td><code>4294967296</code> (4 GB)</td></tr></tbody></table><p>Per-worker memory limit in bytes. <strong>Not yet enforced</strong> — the option is parsed but memory-based eviction/restart is not implemented yet.</p><h2 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h2><p><code>[[rules]]</code> is an array of rule objects. Rules are matched in declaration order — later rules override earlier ones.</p><h3 id="rules-patterns" tabindex="-1"><code>[rules].patterns</code> <a class="header-anchor" href="#rules-patterns" aria-label="Permalink to &quot;`[rules].patterns`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>array of string</code></td><td><code>[]</code></td></tr></tbody></table><p>Glob patterns for matching file paths:</p><ul><li><code>*</code> — matches one or more characters in a path segment</li><li><code>?</code> — matches a single character in a path segment</li><li><code>**</code> — matches any number of path segments, including zero</li><li><code>{}</code> — groups conditions (e.g., <code>**/*.{h,cpp}</code>)</li><li><code>[]</code> — character range (e.g., <code>example.[0-9]</code>)</li><li><code>[!...]</code> — negated character range</li></ul><h3 id="rules-append" tabindex="-1"><code>[rules].append</code> <a class="header-anchor" href="#rules-append" aria-label="Permalink to &quot;`[rules].append`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>array of string</code></td><td><code>[]</code></td></tr></tbody></table><p>Flags to append to the compilation command. Example: <code>[&quot;-std=c++20&quot;, &quot;-DNDEBUG&quot;]</code>.</p><h3 id="rules-remove" tabindex="-1"><code>[rules].remove</code> <a class="header-anchor" href="#rules-remove" aria-label="Permalink to &quot;`[rules].remove`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Default</th></tr></thead><tbody><tr><td><code>array of string</code></td><td><code>[]</code></td></tr></tbody></table><p>Flags to remove from the compilation command. Example: <code>[&quot;-Wall&quot;, &quot;-Werror&quot;]</code>.</p><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">project</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">max_active_file = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">compile_commands_paths = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;${workspace}/build&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;${workspace}/cmake-build-debug&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">clang_tidy = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rules</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">patterns = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;**/*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">append = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-std=c++23&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rules</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">patterns = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;**/test/**&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">append = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-DTEST_MODE&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div>',53)])])}const b=t(r,[["render",d]]);export{u as __pageData,b as default};
